1	export type Scenario = {
2	  customer: { yearsWithMHPCO: number };
3	  steps: any[];
4	};
5	
6	export type ScenarioResult = {
7	  results: any[];
8	};
9	
10	const PROCESSING_FEE = 5;
11	const FIRST_INSURANCE_SURCHARGE = 0.1;
12	const CURSE_SURCHARGE = 0.5;
13	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
14	const HIGH_ENCHANTMENT_THRESHOLD = 5;
15	const LOYALTY_DISCOUNT = 0.2;
16	const LOYALTY_YEARS_THRESHOLD = 2;
17	const FOLLOWUP_DISCOUNT = 0.15;
18	const CLAIM_DEDUCTIBLE = 100;
19	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
20	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
21	const COMPONENT_BLOCK_SIZE = 3;
22	const COMPONENT_BLOCK_PREMIUM = 60;
23	
24	const BASE_PREMIUM: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	  rune: 25,
30	  moonstone: 25,
31	};
32	
33	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
34	
35	const roundUp = (value: number) => Math.ceil(Math.round(value * 1e6) / 1e6);
36	
37	const componentBasePremium = (count: number, perUnit: number) => {
38	  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
39	  return count * perUnit;
40	};
41	
42	type PremiumEntry = { base: number; surchargePct: number };
43	
44	const itemSurchargePct = (item: any): number =>
45	  FIRST_INSURANCE_SURCHARGE +
46	  (item.cursed ? CURSE_SURCHARGE : 0) +
47	  ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
48	    ? HIGH_ENCHANTMENT_SURCHARGE
49	    : 0);
50	
51	const singleItemEntry = (item: any): PremiumEntry => ({
52	  base: BASE_PREMIUM[item.type],
53	  surchargePct: itemSurchargePct(item),
54	});
55	
56	const componentGroupEntry = (type: string, count: number): PremiumEntry => ({
57	  base: componentBasePremium(count, BASE_PREMIUM[type]),
58	  surchargePct: FIRST_INSURANCE_SURCHARGE,
59	});
60	
61	const premiumEntries = (items: any[]): PremiumEntry[] => {
62	  const singles = items
63	    .filter((item) => !COMPONENT_TYPES.has(item.type))
64	    .map(singleItemEntry);
65	  const componentCounts = items
66	    .filter((item) => COMPONENT_TYPES.has(item.type))
67	    .reduce<Record<string, number>>(
68	      (counts, item) => ({ ...counts, [item.type]: (counts[item.type] ?? 0) + 1 }),
69	      {},
70	    );
71	  const componentGroups = Object.entries(componentCounts).map(
72	    ([type, count]) => componentGroupEntry(type, count),
73	  );
74	  return [...singles, ...componentGroups];
75	};
76	
77	const policyModifierPct = (
78	  customer: Scenario["customer"],
79	  isFollowUp: boolean,
80	): number => {
81	  const loyalty =
82	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? LOYALTY_DISCOUNT : 0;
83	  const followUp = isFollowUp ? FOLLOWUP_DISCOUNT : 0;
84	  return -(loyalty + followUp);
85	};
86	
87	const quote = (
88	  step: any,
89	  customer: Scenario["customer"],
90	  isFollowUp: boolean,
91	) => {
92	  const policyPct = policyModifierPct(customer, isFollowUp);
93	  const total = premiumEntries(step.items).reduce(
94	    (sum, { base, surchargePct }) => sum + base * (1 + surchargePct + policyPct),
95	    PROCESSING_FEE,
96	  );
97	  return { premium: roundUp(total) };
98	};
99	
100	const previousQuoteCount = (steps: any[], index: number): number =>
101	  steps.slice(0, index).filter((step) => step.op === "quote").length;
102	
103	const damagePayout = (amount: number, item: any): number => {
104	  let reimbursed = amount;
105	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD) {
106	    reimbursed = amount * HIGH_ENCHANTMENT_PAYOUT_RATE;
107	  }
108	  return Math.max(0, reimbursed - CLAIM_DEDUCTIBLE);
109	};
110	
111	const claim = (step: any, policyItems: any[]): { payout: number } => {
112	  const total = step.incident.damages.reduce((sum: number, d: any) => {
113	    const item = policyItems.find((it) => it.type === d.itemType);
114	    return sum + damagePayout(d.amount, item);
115	  }, 0);
116	  return { payout: Math.floor(total) };
117	};
118	
119	export const runScenario = (scenario: Scenario): ScenarioResult => {
120	  const results = scenario.steps.map((step, index) => {
121	    if (step.op === "quote") {
122	      const isFollowUp = previousQuoteCount(scenario.steps, index) > 0;
123	      return quote(step, scenario.customer, isFollowUp);
124	    }
125	    if (step.op === "claim") {
126	      const policyStep = scenario.steps[step.policy];
127	      return claim(step, policyStep.items);
128	    }
129	    return {};
130	  });
131	  return { results };
132	};
